import React, { type FC, type PropsWithChildren, useMemo } from "react";
import { View } from "react-native";
import { uniqueId } from "lodash";
import ErrorMessage from "../ErrorMessage";
import type {IKitsContainer} from "@lmb/kitsconcerto-types";
import Addons from "../Addons";
import {
    FormControl,
    FormControlHelper,
    FormControlHelperText,
    FormControlLabelText,

} from "@lmb/kitsconcertomobile"
import { Label } from "../..";

const KitsContainer: FC<PropsWithChildren<IKitsContainer>> = ({
                                                                  id,
                                                                  helperText,
                                                                  className,
                                                                  children,
                                                                  rightAddon,
                                                                  leftAddon,
                                                                  errors,
                                                                  invalid,
                                                                  required,
                                                                  hideError,
                                                                  additionalClassName,
                                                                  label,
                                                                  isFloatedLabel,
                                                                  containerStyle,
                                                                  disabled,
                                                              }) => {
    // Generate a unique element ID (for parity with web; not used in native labels)
    const elementId = id ? `${id}_element` : uniqueId("element_");

    // Derive label placement from the label prop
    const placement = useMemo(() => {
        if (label && typeof label === 'object' && 'placement' in label) {
            return label.placement; // "RL" | "B" | "T"
        }
        return "T"; // default: top
    }, [label]);

    // Determine layout direction based on placement
    // T = top (column, label first), B = bottom (column-reverse), RL = side-by-side (row)
    const isHorizontal = placement === "RL";
    const isBottom = placement === "B";

    const labelElement = !isFloatedLabel ? (
        <Label isFormControl label={label} elementId={elementId} />
    ) : null;

    const contentElement = (
        <Addons additionalClassName={additionalClassName} leftAddon={leftAddon} rightAddon={rightAddon} invalid={invalid}>
            {children}
        </Addons>
    );



    return(
        <FormControl
            isInvalid={invalid}
            size="md"
            isDisabled={disabled}
            isReadOnly={disabled}
            isRequired={required}
            style={{width:'100%', gap: 4}}
        >
            {isHorizontal ? (
                <View style={{ flexDirection: 'row', alignItems: 'center', gap: 8, width: '100%' }}>
                    {labelElement}
                    <View style={{ flex: 1 }}>{contentElement}</View>
                </View>
            ) : isBottom ? (
                <>
                    {contentElement}
                    {labelElement}
                </>
            ) : (
                <>
                    {labelElement}
                    {contentElement}
                </>
            )}
            {helperText && typeof helperText !== "function" && <FormControlHelper>
                <FormControlHelperText>
                    {helperText}
                </FormControlHelperText>
            </FormControlHelper>}

            {!hideError && <ErrorMessage invalid={invalid} errors={errors} />}
        </FormControl>
    )
};

export default KitsContainer;
